def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_travel_time(origin, destination):
        return np.linalg.norm(origin - destination) / truck_speed

    best_node = None
    min_total_delay = float('inf')

    for i, customer_pos in enumerate(unvisited_customers):
        direct_travel_time = calculate_travel_time(cur_truck_pos, customer_pos)
        estimated_arrival_time = current_time + direct_travel_time
        start, end = time_windows[i]

        total_delay = 0
        if estimated_arrival_time < start:
            waiting_time = start - estimated_arrival_time
        else:
            waiting_time = 0  # no waiting if we're late or on time

        for truck_pos in all_truck_pos:
            if np.array_equal(truck_pos, cur_truck_pos):
                continue  # skip the current truck's position
            indirect_travel_time = calculate_travel_time(truck_pos, customer_pos)
