            total_delay += synchronize_time + waiting_time

        if total_delay < min_total_delay:
            min_total_delay = total_delay
            best_node = i

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(p1, p2):
        return np.linalg.norm(p1 - p2)

    if len(unvisited_customers) == 0:
        return None

    time_to_reach = [(calculate_distance(cur_truck_pos, customer) / truck_speed) for customer in unvisited_customers]
    arrival_times = [current_time + time for time in time_to_reach]

    scores = []

    # Calculate a score for each customer based on time windows and distances
    for idx, customer in enumerate(unvisited_customers):
        window_start, window_end = time_windows[idx]
        arrival_time = arrival_times[idx]

        if arrival_time < window_start:
            wait_time = window_start - arrival_time
            score = wait_time + time_to_reach[idx] * 1.2  # Penalty for waiting, but less than missing the window
        elif arrival_time > window_end:
            penalty = (arrival_time - window_end) * 10  # High penalty for missing the window
            score = penalty + time_to_reach[idx]
        else:
            score = time_to_reach[idx]  # No penalty if within the window

        scores.append(score)

    # Find the best customer to minimize the score
    best_node = np.argmin(scores)

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(point1, point2):
        return np.sqrt(np.sum((point1 - point2)**2))

    best_node = None
    min_cost = float('inf')

    for i, customer_pos in enumerate(unvisited_customers):
        travel_time = calculate_distance(cur_truck_pos, customer_pos) / truck_speed
        arrive_time = current_time + travel_time
        earliest, latest = time_windows[i]

        if arrive_time > latest:
            continue

        waiting_time = max(0, earliest - arrive_time)
        cost = waiting_time + travel_time  # simple cost: travel time plus any waiting time

        if cost < min_cost:
            min_cost = cost
            best_node = i

    return best_node
